// isValidURL checks if the URL is valid and not pointing to restricted addresses
func isValidURL(targetURL *url.URL) bool {
	// Check for restricted schemes
	switch targetURL.Scheme {
	case "file":
		return false
	case "ftp":
		return false
	case "gopher":
		return false
	case "mailto":
		return false
	case "data":
		return false
	}

	// Resolve the host
	host := targetURL.Hostname()
	if host == "" {
		return false
	}

	// Get IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return false
	}

	// Check each IP address
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return false
		}
	}

	return true
}

// isPrivateIP checks if an IP address is private or reserved
func isPrivateIP(ip net.IP) bool {
	// Check for loopback addresses
	if ip.IsLoopback() {
		return true
	}

	// Check for link-local addresses
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for private IP ranges
	private4Ranges := []*net.IPNet{
		{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},     // 10.0.0.0/8
		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},  // 172.16.0.0/12
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)}, // 192.168.0.0/16
		{IP: net.ParseIP("127.0.0.0"), Mask: net.CIDRMask(8, 32)},    // 127.0.0.0/8 (loopback)
		{IP: net.ParseIP("0.0.0.0"), Mask: net.CIDRMask(8, 32)},      // 0.0.0.0/8 (current network)
	}

	for _, cidr := range private4Ranges {
		if cidr.Contains(ip) {
			return true
		}
	}

	// Check for IPv6 local addresses
	if ip.To4() == nil {
		// Use IsPrivate() for IPv6 private ranges (Go 1.17+)
		if ip.IsPrivate() {
			return true
		}

		// Check for IPv6 link-local ranges
		if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}

		// Check for IPv6 unique local addresses (fc00::/7)
		if len(ip) == 16 && ip[0]&0xfe == 0xfc {
			return true
		}
	}

	// Check for reserved addresses
	reservedIPs := []*net.IPNet{
		{IP: net.ParseIP("224.0.0.0"), Mask: net.CIDRMask(4, 32)},  // 224.0.0.0/4 (multicast)
		{IP: net.ParseIP("240.0.0.0"), Mask: net.CIDRMask(4, 32)},  // 240.0.0.0/4 (reserved)
	}

	for _, cidr := range reservedIPs {
		if cidr.Contains(ip) {
			return true
		}
	}

	return false
}

