		})
	}

	// Check for SSRF vulnerabilities: prevent internal IP access
	ip := u.Hostname()
	if isPrivateIP(ip) {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Private IP addresses are not allowed",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
		Transport: &http.Transport{
			DisableCompression: true,
			DisableKeepAlives:  true,
		},
	}

	// Create GET request to test webhook
	testReq, err := http.NewRequestWithContext(context.Background(), "GET", req.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(Response{
			Success: false,
			Message: "Failed to create test request",
		})
	}

	// Send test request
	resp, err := client.Do(testReq)
	if err != nil {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Webhook test failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is in the 2xx range
	if resp.StatusCode >= 200 && resp.StatusCode < 300 {
		return ctx.Status(fiber.StatusOK).JSON(Response{
			Success: true,
			Message: "Webhook configured successfully",
		})
	} else {
		return ctx.Status(fiber.StatusBadGateway).JSON(Response{
			Success: false,
			Message: fmt.Sprintf("Webhook returned status code: %d", resp.StatusCode),
		})
	}
}

// isPrivateIP checks if the hostname resolves to a private or internal IP address
func isPrivateIP(hostname string) bool {
	ip := net.ParseIP(hostname)
	if ip == nil {
		// If it's not an IP address, it's a hostname and we allow it
		return false
	}

	// Check for private IP ranges
	privateNetworks := []string{
		"10.0.0.0/8",     // Class A private network
		"172.16.0.0/12",  // Class B private network
		"192.168.0.0/16", // Class C private network
		"127.0.0.0/8",    // Loopback
		"0.0.0.0/32",     // Current network
		"169.254.0.0/16", // Link-local
	}

	for _, cidr := range privateNetworks {
		_, block, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if block.Contains(ip) {
			return true
		}
	}

	return false
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	app.Listen(":3000")
}

